import asyncio
import json
import logging
import math
import re
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        behavior_metrics = _compute_behavior_metrics(agents, results, max_steps, num_gens)
        if training_logger:
            training_logger.log_rollout_done(
                step,
                len(results),
                rewards,
                rollout_stats=rollout_stats,
                behavior_metrics=behavior_metrics,
            )

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        # Write trajectories to file (after logprobs are computed)
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer, logprobs_list=logprobs_list)

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _compute_behavior_metrics(agents, results, max_steps, num_generations=8):
    total = len(results)
    if total == 0:
        return {}

    rewards = [float(r.get("trajectory_reward", 0.0)) for r in results if isinstance(r, dict)]
    reward_mean = sum(rewards) / len(rewards) if rewards else 0.0
    reward_variance = math.sqrt(sum((r - reward_mean) ** 2 for r in rewards) / len(rewards)) if rewards else 0.0

    # pass@1 and pass@K: group rewards by prompt (num_generations per prompt)
    pass1 = 0.0
    passK = 0.0
    if num_generations > 0 and total >= num_generations:
        num_prompts = total // num_generations
        pass1_count = 0
        passK_count = 0
        for p in range(num_prompts):
            group = rewards[p * num_generations:(p + 1) * num_generations]
            if any(r >= 1.0 for r in group):
                pass1_count += 1
            if all(r >= 1.0 for r in group):
                passK_count += 1
        pass1 = pass1_count / num_prompts
        passK = passK_count / num_prompts

    finish_count = 0
    finish_numeric_count = 0
    calculate_count = 0
    answer_count = 0
    truncation_count = 0
    parser_error_count = 0
    malformed_tool_count = 0
    synthetic_finish_count = 0
    calculator_error_count = 0
    symbolic_calculator_error_count = 0
    successful_calculate_count = 0
    no_finish_count = 0
    valid_finish_count = 0
    response_lengths = []
    agent_steps = []

    for agent, result in zip(agents, results):
        calls = _extract_tool_calls(agent)
        finish_calls = [c for c in calls if c.get("name") == "finish"]
        calculate_calls = [c for c in calls if c.get("name") == "calculate"]
        has_finish = bool(finish_calls)
        has_calculate = bool(calculate_calls)
        finish_values = [_finish_value(c) for c in finish_calls]
        has_numeric_finish = any(_is_numeric_answer(v) for v in finish_values)
        has_answer = any(_has_answer_text(v) for v in finish_values)

        if has_finish:
            finish_count += 1
        if has_numeric_finish:
            finish_numeric_count += 1
        if has_calculate:
            calculate_count += 1
        if has_answer:
            answer_count += 1

        step_infos = [getattr(step, "info", {}) for step in getattr(agent.trajectory, "steps", [])]
        reward_components = [info.get("reward_components") for info in step_infos if info.get("reward_components")]
        if any(info.get("parse_error_type") for info in step_infos):
            parser_error_count += 1
        if any(info.get("malformed_tool_call") for info in step_infos):
            malformed_tool_count += 1
        if any(info.get("synthetic_finish") for info in step_infos):
            synthetic_finish_count += 1
        if any((comp.get("calculator_errors") or 0) > 0 for comp in reward_components):
            calculator_error_count += 1
        if any((comp.get("symbolic_calculator_errors") or 0) > 0 for comp in reward_components):
            symbolic_calculator_error_count += 1
        if any((comp.get("successful_calculates") or 0) > 0 for comp in reward_components):
            successful_calculate_count += 1
        if any("no_finish" in (comp.get("events") or []) for comp in reward_components):
            no_finish_count += 1
        if any("valid_finish" in (comp.get("events") or []) for comp in reward_components):
            valid_finish_count += 1

        if isinstance(result, dict):
            steps = int(result.get("metrics", {}).get("steps", 0) or 0)
            reward = float(result.get("trajectory_reward", 0.0) or 0.0)
            if steps >= max_steps and reward == 0.0:
                truncation_count += 1
            agent_steps.append(steps)
            response_lengths.append(len(result.get("response_tokens", [])))

    return {
        "finish_rate": finish_count / total,
        "finish_format_rate": finish_numeric_count / finish_count if finish_count else 0.0,
        "tool_usage_rate": calculate_count / total,
        "truncation_rate": truncation_count / total,
        "answer_coverage": answer_count / total,
        "reward_variance": reward_variance,
        "parser_error_rate": parser_error_count / total,
        "malformed_tool_rate": malformed_tool_count / total,
        "synthetic_finish_rate": synthetic_finish_count / total,
        "calculator_error_rate": calculator_error_count / total,
        "symbolic_calculator_error_rate": symbolic_calculator_error_count / total,
        "successful_calculate_rate": successful_calculate_count / total,
        "no_finish_rate": no_finish_count / total,
        "valid_finish_rate": valid_finish_count / total,
        "avg_agent_steps": sum(agent_steps) / len(agent_steps) if agent_steps else 0.0,
        "completion_length_mean": sum(response_lengths) / len(response_lengths) if response_lengths else 0.0,
        "pass1": pass1,
        "passK": passK,
    }


def _extract_tool_calls(agent):
    calls = []
    for msg in getattr(agent, "chat_completions", []) or []:
        if not isinstance(msg, dict) or msg.get("role") != "assistant":
            continue
        content = msg.get("content") or ""
        for match in re.finditer(r"<tool_call>\s*(\{.*?\})\s*</tool_call>", content, flags=re.S):
            try:
                call = json.loads(match.group(1))
            except json.JSONDecodeError:
                continue
            name = str(call.get("name", "")).lower()
            args = call.get("arguments") or {}
            calls.append({"name": name, "arguments": args})
    return calls


def _finish_value(call):
    args = call.get("arguments") or {}
    if not isinstance(args, dict):
        return ""
    if "response" in args:
        return args["response"]
    if "answer" in args:
        return args["answer"]
    if len(args) == 1:
        return next(iter(args.values()))
    return ""


def _is_numeric_answer(value):
    text = str(value).strip()
    return bool(
        re.fullmatch(r"[-+]?\d+(?:\.\d+)?(?:\s*/\s*[-+]?\d+(?:\.\d+)?)?", text)
        or re.fullmatch(r"\\frac\{[-+]?\d+\}\{[-+]?\d+\}", text)
    )


def _has_answer_text(value):
    return bool(re.search(r"[-+]?\d+(?:\.\d+)?|\\frac\{[-+]?\d+\}\{[-+]?\d+\}", str(value)))


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

"""
VERL training monitor for rllm-monitor.
Reads verl_metrics.jsonl (VERL's file logger output) for structured per-step metrics.

Usage:
    python rllm_train/monitor_agent_verl.py stream <output_dir>
    python rllm_train/monitor_agent_verl.py oneshot <output_dir> [--last N]
"""

import json
import os
import re
import sys
import time

_COMPLETE_RE = re.compile(r"Training (?:completed|finished)", re.I)
_ERROR_RE = re.compile(
    r"Traceback|out of memory|Killed|SIGTERM|SIGKILL|"
    r"RuntimeError|RayActorError|Actor died|"
    r"CUDA error|NCCL error|HCCL",
    re.I,
)
_PROGRESS_RE = re.compile(r"Training Progress:\s+(\d+)%", re.I)

# Key metrics to always report, in display order
_KEY_METRICS = [
    "critic/score/mean",
    "critic/score/max",
    "critic/score/min",
    "critic/rewards/mean",
    "actor/pg_loss",
    "actor/entropy",
    "actor/grad_norm",
    "actor/pg_clipfrac",
    "actor/ppo_kl",
    "actor/lr",
    "response_length/mean",
    "response_length/clip_ratio",
    "perf/mfu/actor_infer",
]


def _emit(line: str) -> None:
    print(line, flush=True)


def _metrics_jsonl_path(output_dir: str) -> str:
    return os.path.join(output_dir, "verl_metrics.jsonl")


def _training_log_path(output_dir: str) -> str:
    return os.path.join(output_dir, "training_log.txt")


def _format_step(step_data: dict) -> str:
    """Format all key metrics for a step into a single line."""
    s = step_data["step"]
    data = step_data["data"]
    parts = [f"Step {s}"]
    for key in _KEY_METRICS:
        v = data.get(key)
        if v is not None:
            if isinstance(v, float):
                parts.append(f"{key}={v:.4f}")
            else:
                parts.append(f"{key}={v}")
    return " | ".join(parts)


def _format_step_compact(step_data: dict) -> str:
    """Compact format: Step N | R 0.xxx | Loss 0.xxx | Grad 0.xxx."""
    s = step_data["step"]
    data = step_data["data"]
    parts = [f"Step {s}"]
    score = data.get("critic/score/mean")
    if score is not None:
        parts.append(f"R {score:.4f}")
    loss = data.get("actor/pg_loss")
    if loss is not None:
        parts.append(f"Loss {loss:+.4f}")
    grad = data.get("actor/grad_norm")
    if grad is not None:
        parts.append(f"Grad {grad:.4f}")
    ent = data.get("actor/entropy")
    if ent is not None:
        parts.append(f"Ent {ent:.3f}")
    clen = data.get("response_length/mean")
    if clen is not None:
        parts.append(f"Len {clen:.0f}")
    return " | ".join(parts)


def _check_errors(log_path: str) -> str | None:
    """Scan training_log.txt for fatal errors. Returns error message or None."""
    if not os.path.exists(log_path):
        return None
    try:
        with open(log_path, "r", errors="replace") as f:
            # Only check last 5KB for efficiency
            f.seek(max(0, os.path.getsize(log_path) - 5120))
            tail = f.read()
    except OSError:
        return None
    for line in tail.splitlines():
        if _COMPLETE_RE.search(line):
            return "complete"
        if _ERROR_RE.search(line):
            if not re.search(r"WARNING|UserWarning|FutureWarning|Deprecated|truncation.*error|OMP_NUM_THREADS", line, re.I):
                # Avoid false positives from config values and known benign warnings
                return line.strip()[:200]
    return None


def stream(output_dir: str, timeout: int = 3600) -> None:
    """Stream verl_metrics.jsonl, reporting each new step with all metrics."""
    jsonl_path = _metrics_jsonl_path(output_dir)
    log_path = _training_log_path(output_dir)
    last_step = 0
    start = time.time()

    while not os.path.exists(jsonl_path):
        if time.time() - start > 300:
            _emit(f"TIMEOUT: {jsonl_path} did not appear within 300s")
            return
        time.sleep(3)

    try:
        st = os.stat(jsonl_path)
        inode = st.st_ino
        pos = st.st_size
    except OSError:
        pos = 0

    last_data_time = time.time()

    while True:
        if time.time() - start > timeout:
            _emit("TIMEOUT: monitor stream exceeded time limit")
            return

        # Check for errors every 15s
        if int(time.time()) % 15 == 0:
            err = _check_errors(log_path)
            if err == "complete":
                _emit("DETECTED: Training completed")
                return
            elif err:
                _emit(f"ERROR: {err}")
                return

        try:
            st = os.stat(jsonl_path)
            current_inode = st.st_ino
            current_size = st.st_size
        except OSError:
            time.sleep(3)
            continue

        if current_inode != inode or current_size < pos:
            inode = current_inode
            pos = 0
            last_step = 0

        if current_size > pos:
            last_data_time = time.time()
            try:
                with open(jsonl_path, "r", errors="replace") as f:
                    f.seek(pos)
                    data = f.read()
                    pos = f.tell()
            except (OSError, ValueError):
                time.sleep(3)
                continue

            for line in data.splitlines():
                if not line.strip():
                    continue
                try:
                    step_data = json.loads(line)
                    s = step_data["step"]
                    if s > last_step:
                        last_step = s
                        _emit(_format_step_compact(step_data))
                except (json.JSONDecodeError, KeyError):
                    continue
        else:
            if time.time() - last_data_time > 600:
                _emit("WARN: no new metrics for 10 minutes, training may be stalled")

        time.sleep(5)


def oneshot(output_dir: str, last_n: int = 1) -> None:
    """One-shot: read last N steps from verl_metrics.jsonl."""
    jsonl_path = _metrics_jsonl_path(output_dir)
    log_path = _training_log_path(output_dir)

    # Report metrics first (if available)
    if os.path.exists(jsonl_path):
        try:
            with open(jsonl_path, "r", errors="replace") as f:
                lines = [l.strip() for l in f.readlines() if l.strip()]
        except OSError:
            lines = []

        if lines:
            for line in lines[-last_n:]:
                try:
                    _emit(_format_step_compact(json.loads(line)))
                except json.JSONDecodeError:
                    continue
            _emit("---")
            try:
                _emit(_format_step(json.loads(lines[-1])))
            except json.JSONDecodeError:
                pass
            return

    # No metrics yet: check for progress or errors
    if os.path.exists(log_path):
        try:
            with open(log_path, "r", errors="replace") as f:
                f.seek(max(0, os.path.getsize(log_path) - 2048))
                tail = f.read()
        except OSError:
            tail = ""

        # Check completion
        if _COMPLETE_RE.search(tail):
            _emit("DETECTED: Training completed")
            return

        # Check progress
        m = _PROGRESS_RE.findall(tail)
        if m:
            _emit(f"PROGRESS: {m[-1]}% complete")
            return

        # Check errors (only when no metrics exist)
        err = _check_errors(log_path)
        if err:
            _emit(f"DETECTED: {err}")
            return

    _emit("ONESHOT: no metrics yet (model loading)")


if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="VERL training monitor (reads verl_metrics.jsonl)")
    sub = parser.add_subparsers(dest="mode")

    p_stream = sub.add_parser("stream")
    p_stream.add_argument("output_dir", help="Training output directory (rllm_train/output/runs/<run_id>)")
    p_stream.add_argument("--timeout", type=int, default=3600)

    p_shot = sub.add_parser("oneshot")
    p_shot.add_argument("output_dir", help="Training output directory")
    p_shot.add_argument("--last", type=int, default=1)

    args = parser.parse_args()
    if args.mode == "stream":
        stream(args.output_dir, timeout=args.timeout)
    elif args.mode == "oneshot":
        oneshot(args.output_dir, last_n=args.last)
    else:
        parser.print_help()
        sys.exit(1)

import asyncio
import json
import logging
import math
import re
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        behavior_metrics = _compute_behavior_metrics(agents, results, max_steps, num_gens)
        if training_logger:
            training_logger.log_rollout_done(
                step,
                len(results),
                rewards,
                rollout_stats=rollout_stats,
                behavior_metrics=behavior_metrics,
            )

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        # Write trajectories to file (after logprobs are computed)
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer, logprobs_list=logprobs_list)

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _compute_behavior_metrics(agents, results, max_steps, num_generations=8):
    total = len(results)
    if total == 0:
        return {}

    rewards = [float(r.get("trajectory_reward", 0.0)) for r in results if isinstance(r, dict)]
    reward_mean = sum(rewards) / len(rewards) if rewards else 0.0
    reward_variance = math.sqrt(sum((r - reward_mean) ** 2 for r in rewards) / len(rewards)) if rewards else 0.0

    # pass@1 and pass@K: group rewards by prompt (num_generations per prompt)
    pass1 = 0.0
    passK = 0.0
    if num_generations > 0 and total >= num_generations:
        num_prompts = total // num_generations
        pass1_count = 0
        passK_count = 0
        for p in range(num_prompts):
            group = rewards[p * num_generations:(p + 1) * num_generations]
            if any(r >= 1.0 for r in group):
                pass1_count += 1
            if all(r >= 1.0 for r in group):
                passK_count += 1
        pass1 = pass1_count / num_prompts
        passK = passK_count / num_prompts

    finish_count = 0
    finish_numeric_count = 0
    calculate_count = 0
    answer_count = 0
    truncation_count = 0
    parser_error_count = 0
    malformed_tool_count = 0
    synthetic_finish_count = 0
    calculator_error_count = 0
    symbolic_calculator_error_count = 0
    successful_calculate_count = 0
    no_finish_count = 0
    valid_finish_count = 0
    response_lengths = []
    agent_steps = []

    for agent, result in zip(agents, results):
        calls = _extract_tool_calls(agent)
        finish_calls = [c for c in calls if c.get("name") == "finish"]
        calculate_calls = [c for c in calls if c.get("name") == "calculate"]
        has_finish = bool(finish_calls)
        has_calculate = bool(calculate_calls)
        finish_values = [_finish_value(c) for c in finish_calls]
        has_numeric_finish = any(_is_numeric_answer(v) for v in finish_values)
        has_answer = any(_has_answer_text(v) for v in finish_values)

        if has_finish:
            finish_count += 1
        if has_numeric_finish:
            finish_numeric_count += 1
        if has_calculate:
            calculate_count += 1
        if has_answer:
            answer_count += 1

        step_infos = [getattr(step, "info", {}) for step in getattr(agent.trajectory, "steps", [])]
        reward_components = [info.get("reward_components") for info in step_infos if info.get("reward_components")]
        if any(info.get("parse_error_type") for info in step_infos):
            parser_error_count += 1
        if any(info.get("malformed_tool_call") for info in step_infos):
            malformed_tool_count += 1
        if any(info.get("synthetic_finish") for info in step_infos):
            synthetic_finish_count += 1
        if any((comp.get("calculator_errors") or 0) > 0 for comp in reward_components):
            calculator_error_count += 1
        if any((comp.get("symbolic_calculator_errors") or 0) > 0 for comp in reward_components):
            symbolic_calculator_error_count += 1
        if any((comp.get("successful_calculates") or 0) > 0 for comp in reward_components):
            successful_calculate_count += 1
        if any("no_finish" in (comp.get("events") or []) for comp in reward_components):
            no_finish_count += 1
        if any("valid_finish" in (comp.get("events") or []) for comp in reward_components):
            valid_finish_count += 1

        if isinstance(result, dict):
            steps = int(result.get("metrics", {}).get("steps", 0) or 0)
            reward = float(result.get("trajectory_reward", 0.0) or 0.0)
            if steps >= max_steps and reward == 0.0:
                truncation_count += 1
            agent_steps.append(steps)
            response_lengths.append(len(result.get("response_tokens", [])))

    return {
        "finish_rate": finish_count / total,
        "finish_format_rate": finish_numeric_count / finish_count if finish_count else 0.0,
        "tool_usage_rate": calculate_count / total,
        "truncation_rate": truncation_count / total,
        "answer_coverage": answer_count / total,
        "reward_variance": reward_variance,
        "parser_error_rate": parser_error_count / total,
        "malformed_tool_rate": malformed_tool_count / total,
        "synthetic_finish_rate": synthetic_finish_count / total,
        "calculator_error_rate": calculator_error_count / total,
        "symbolic_calculator_error_rate": symbolic_calculator_error_count / total,
        "successful_calculate_rate": successful_calculate_count / total,
        "no_finish_rate": no_finish_count / total,
        "valid_finish_rate": valid_finish_count / total,
        "avg_agent_steps": sum(agent_steps) / len(agent_steps) if agent_steps else 0.0,
        "completion_length_mean": sum(response_lengths) / len(response_lengths) if response_lengths else 0.0,
        "pass1": pass1,
        "passK": passK,
    }


def _extract_tool_calls(agent):
    calls = []
    for msg in getattr(agent, "chat_completions", []) or []:
        if not isinstance(msg, dict) or msg.get("role") != "assistant":
            continue
        content = msg.get("content") or ""
        for match in re.finditer(r"<tool_call>\s*(\{.*?\})\s*</tool_call>", content, flags=re.S):
            try:
                call = json.loads(match.group(1))
            except json.JSONDecodeError:
                continue
            name = str(call.get("name", "")).lower()
            args = call.get("arguments") or {}
            calls.append({"name": name, "arguments": args})
    return calls


def _finish_value(call):
    args = call.get("arguments") or {}
    if not isinstance(args, dict):
        return ""
    if "response" in args:
        return args["response"]
    if "answer" in args:
        return args["answer"]
    if len(args) == 1:
        return next(iter(args.values()))
    return ""


def _is_numeric_answer(value):
    text = str(value).strip()
    return bool(
        re.fullmatch(r"[-+]?\d+(?:\.\d+)?(?:\s*/\s*[-+]?\d+(?:\.\d+)?)?", text)
        or re.fullmatch(r"\\frac\{[-+]?\d+\}\{[-+]?\d+\}", text)
    )


def _has_answer_text(value):
    return bool(re.search(r"[-+]?\d+(?:\.\d+)?|\\frac\{[-+]?\d+\}\{[-+]?\d+\}", str(value)))


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

